krpano.action:
set(hotspot[%1].alpha, 0.6); 
set(hotspot[%1].scale, 0.3);
tween(hotspot[%1].alpha, 0.0, 2.0, easeOutQuad);
tween(hotspot[%1].scale, 1.3, 2.0, easeOutQuad, action_pulse(%1));

txtadd(bname, %1, '_base');
addhotspot(get(bname));

set(hotspot[get(bname)].type, 'text');
copy(hotspot[get(bname)].ath, hotspot[%1].ath);
copy(hotspot[get(bname)].atv, hotspot[%1].atv);

set(hotspot[get(bname)].width, 50); set(hotspot[get(bname)].height, 50);
set(hotspot[get(bname)].bgroundedge, 25);
set(hotspot[get(bname)].bgcolor, 0xFF0000); 
set(hotspot[get(bname)].bgalpha, 0.5);
set(hotspot[get(bname)].enabled, false); set(hotspot[get(bname)].distorted, true);

txtadd(pulse_cmd, 'action_pulse(', get(bname), ')');
set(hotspot[get(bname)].onloaded, get(pulse_cmd));

        txtadd(lname, %1, '_lbl');
        addhotspot(get(lname));

        set(hotspot[get(lname)].type, 'text');

        txtadd(myhtml, '
📍 ', get(hotspot[%1].tooltip), '');
        set(hotspot[get(lname)].html, get(myhtml)); 

        copy(hotspot[get(lname)].ath, hotspot[%1].ath); 
        copy(hotspot[get(lname)].atv, hotspot[%1].atv);

        set(hotspot[get(lname)].oy, 18); 
        set(hotspot[get(lname)].edge, 'top');
        set(hotspot[get(lname)].distorted, false); 
        set(hotspot[get(lname)].enabled, false);
        set(hotspot[get(lname)].zorder, 100);
        set(hotspot[get(lname)].bg, false);
